<template>
  <div class="log-list-container">
    <el-card>
      <div class="filter-container">
        <el-form :inline="true" :model="listQuery" class="demo-form-inline">
          <el-form-item label="操作人">
            <el-input v-model="listQuery.operator" placeholder="操作人" clearable></el-input>
          </el-form-item>
          <el-form-item label="操作类型">
            <el-select v-model="listQuery.type" placeholder="全部类型" clearable>
              <el-option label="登录" value="login"></el-option>
              <el-option label="添加" value="create"></el-option>
              <el-option label="修改" value="update"></el-option>
              <el-option label="删除" value="delete"></el-option>
              <el-option label="查询" value="query"></el-option>
              <el-option label="导出" value="export"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="模块">
            <el-select v-model="listQuery.module" placeholder="全部模块" clearable>
              <el-option label="商品管理" value="product"></el-option>
              <el-option label="订单管理" value="order"></el-option>
              <el-option label="用户管理" value="user"></el-option>
              <el-option label="优惠券" value="coupon"></el-option>
              <el-option label="轮播图" value="banner"></el-option>
              <el-option label="售后" value="return"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="操作时间">
            <el-date-picker
              v-model="dateRange"
              type="daterange"
              range-separator="至"
              start-placeholder="开始时间"
              end-placeholder="结束时间"
              value-format="yyyy-MM-dd"
            ></el-date-picker>
          </el-form-item>
          <el-form-item>
            <el-button type="primary" @click="handleSearch">查询</el-button>
            <el-button @click="resetQuery">重置</el-button>
          </el-form-item>
        </el-form>
      </div>
      
      <div class="action-container">
        <el-button type="primary" @click="handleExport" icon="el-icon-download">导出日志</el-button>
        <el-button type="warning" @click="handleClear">清理日志</el-button>
      </div>
      
      <el-table
        v-loading="listLoading"
        :data="list"
        border
        highlight-current-row
      >
        <el-table-column prop="id" label="ID" width="80"></el-table-column>
        <el-table-column prop="operator" label="操作人" width="120"></el-table-column>
        <el-table-column label="操作类型" width="120">
          <template slot-scope="scope">
            <el-tag :type="getTypeTagType(scope.row.type)">{{ getTypeText(scope.row.type) }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column label="模块" width="120">
          <template slot-scope="scope">
            <el-tag type="info">{{ getModuleText(scope.row.module) }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="content" label="操作内容" min-width="200"></el-table-column>
        <el-table-column prop="ip" label="IP地址" width="150"></el-table-column>
        <el-table-column prop="userAgent" label="客户端" width="200"></el-table-column>
        <el-table-column prop="createTime" label="操作时间" width="180"></el-table-column>
        <el-table-column label="操作" width="80">
          <template slot-scope="scope">
            <el-button size="mini" @click="handleView(scope.row)">详情</el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!listLoading && list.length === 0" description="暂无数据" />
      
      <div class="pagination-container">
        <el-pagination
          background
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="listQuery.page"
          :page-sizes="[10, 20, 30, 50]"
          :page-size="listQuery.pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="total"
        ></el-pagination>
      </div>
    </el-card>
    
    <el-dialog title="日志详情" :visible.sync="detailVisible" width="600px">
      <el-form :model="detail" label-width="120px" disabled>
        <el-form-item label="操作ID">
          <span>{{ detail.id }}</span>
        </el-form-item>
        <el-form-item label="操作人">
          <span>{{ detail.operator }}</span>
        </el-form-item>
        <el-form-item label="操作类型">
          <el-tag :type="getTypeTagType(detail.type)">{{ getTypeText(detail.type) }}</el-tag>
        </el-form-item>
        <el-form-item label="模块">
          <el-tag type="info">{{ getModuleText(detail.module) }}</el-tag>
        </el-form-item>
        <el-form-item label="操作内容">
          <span>{{ detail.content }}</span>
        </el-form-item>
        <el-form-item label="请求参数">
          <pre>{{ detail.params || '-' }}</pre>
        </el-form-item>
        <el-form-item label="响应结果">
          <pre>{{ detail.result || '-' }}</pre>
        </el-form-item>
        <el-form-item label="IP地址">
          <span>{{ detail.ip }}</span>
        </el-form-item>
        <el-form-item label="客户端">
          <span>{{ detail.userAgent }}</span>
        </el-form-item>
        <el-form-item label="操作时间">
          <span>{{ detail.createTime }}</span>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="detailVisible = false">关闭</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import logApi from '@/api/log'

export default {
  name: 'LogList',
  data() {
    return {
      list: [],
      total: 0,
      listLoading: true,
      listQuery: { page: 1, pageSize: 10, operator: '', type: '', module: '' },
      dateRange: [],
      detailVisible: false,
      detail: {}
    }
  },
  created() {
    this.fetchData()
  },
  methods: {
    fetchData() {
      this.listLoading = true
      const params = { ...this.listQuery }
      if (this.dateRange.length === 2) {
        params.startDate = this.dateRange[0]
        params.endDate = this.dateRange[1]
      }
      logApi.getList(params).then(res => {
        if (res.code === 0) {
          this.list = res.data.list || []
          this.total = res.data.total || 0
        }
        this.listLoading = false
      }).catch(() => {
        this.$message.error('获取数据失败，请稍后重试')
        this.listLoading = false
      })
    },
    handleView(row) {
      logApi.getDetail(row.id).then(res => {
        if (res.code === 0) {
          this.detail = res.data
          this.detailVisible = true
        }
      })
    },
    handleExport() {
      const params = { ...this.listQuery }
      if (this.dateRange.length === 2) {
        params.startDate = this.dateRange[0]
        params.endDate = this.dateRange[1]
      }
      logApi.exportData(params).then(res => {
        const blob = new Blob([res], { type: 'application/vnd.ms-excel' })
        const url = window.URL.createObjectURL(blob)
        const link = document.createElement('a')
        link.href = url
        link.download = `操作日志_${new Date().toLocaleDateString().replace(/\//g, '-')}.xls`
        link.click()
        window.URL.revokeObjectURL(url)
      })
    },
    handleClear() {
      this.$prompt('请输入保留天数（删除更早的日志）', '清理日志', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        inputPattern: /^[1-9]\d*$/,
        inputErrorMessage: '请输入正整数'
      }).then(({ value }) => {
        logApi.clearLogs(value).then(res => {
          if (res.code === 0) {
            this.$message.success('清理成功')
            this.fetchData()
          }
        })
      })
    },
    handleSearch() {
      this.listQuery.page = 1
      this.fetchData()
    },
    resetQuery() {
      this.listQuery = { page: 1, pageSize: 10, operator: '', type: '', module: '' }
      this.dateRange = []
      this.fetchData()
    },
    handleSizeChange(val) {
      this.listQuery.pageSize = val
      this.fetchData()
    },
    handleCurrentChange(val) {
      this.listQuery.page = val
      this.fetchData()
    },
    getTypeText(type) {
      const map = {
        login: '登录',
        create: '添加',
        update: '修改',
        delete: '删除',
        query: '查询',
        export: '导出'
      }
      return map[type] || type
    },
    getTypeTagType(type) {
      const map = {
        login: 'primary',
        create: 'success',
        update: 'info',
        delete: 'danger',
        query: 'warning',
        export: 'warning'
      }
      return map[type] || 'info'
    },
    getModuleText(module) {
      const map = {
        product: '商品管理',
        order: '订单管理',
        user: '用户管理',
        coupon: '优惠券',
        banner: '轮播图',
        return: '售后'
      }
      return map[module] || module
    }
  }
}
</script>

<style scoped>
pre {
  max-height: 150px;
  overflow-y: auto;
  background: #f5f5f5;
  padding: 10px;
  border-radius: 4px;
  font-size: 12px;
}
</style>